52	      0  => PGP3_IDLE_C,
53	      1  => PGP3_SOF_C,
54	      2  => PGP3_EOF_C,
55	      3  => PGP3_SOC_C,
56	      4  => PGP3_EOC_C,
57	      5  => PGP3_SKP_C,
58	      6  => PGP3_USER_C(0),
59	      7  => PGP3_USER_C(1),
60	      8  => PGP3_USER_C(2),
61	      9  => PGP3_USER_C(3),
62	      10 => PGP3_USER_C(4),
63	      11 => PGP3_USER_C(5),
64	      12 => PGP3_USER_C(6),
65	      13 => PGP3_USER_C(7));
66	
67	   constant PGP3_D_HEADER_C : slv(1 downto 0) := "01";
