160	      linkReady      : sl;                -- locRxLinkReady
161	      frameRx        : sl;                -- A good frame was received
162	      frameRxErr     : sl;                -- An errored frame was received
163	      cellError      : sl;                -- A cell error has occurred
164	      linkDown       : sl;                -- A link down event has occurred
165	      linkError      : sl;                -- A link error has occurred
166	      opCodeEn       : sl;                -- Opcode valid
167	      opCodeNumber   : slv(2 downto 0);   -- Opcode number
168	      opCodeData     : slv(47 downto 0);  -- Opcode data
169	      remLinkData    : slv(55 downto 0);  -- Far end side User Data
170	      remRxLinkReady : sl;                -- Far end RX has link
171	      remRxOverflow  : slv(15 downto 0);  -- Far end RX overflow status
172	      remRxPause     : slv(15 downto 0);  -- Far end pause status
