181	      ebData     : slv(63 downto 0);
182	      ebHeader   : slv(1 downto 0);
183	      ebValid    : sl;
184	      ebOverflow : sl;
185	      ebStatus   : slv(8 downto 0);
186	   end record Pgp3RxOutType;
187	
188	   type Pgp3RxOutArray is array (natural range<>) of Pgp3RxOutType;
189	
