255	   begin
256	      ret := not (opCodeData(7 downto 0) +
257	                  opCodeData(15 downto 8) +
258	                  opCodeData(23 downto 16) +
259	                  opCodeData(31 downto 24) +
260	                  opCodeData(39 downto 32) +
261	                  opCodeData(47 downto 40));
262	      return ret;
263	   end function;
