197	   function pgp4MakeLinkInfo (
198	      locRxFifoCtrl  : AxiStreamCtrlArray;
199	      locRxLinkReady : sl)
200	      return slv
201	   is
202	      variable ret : slv(PGP4_LINKINFO_FIELD_C) := (others => '0');
203	   begin
204	      ret(7 downto 0) := PGP4_VERSION_C;
205	      ret(8)          := locRxLinkReady;
206	      for i in locRxFifoCtrl'range loop
207	         ret(i+16) := locRxFifoCtrl(i).pause;
208	      end loop;
209	      return ret;
210	   end function;
211	
212	   procedure pgp4ExtractLinkInfo (
213	      linkInfo       : in    slv(PGP4_LINKINFO_FIELD_C);
214	      remRxFifoCtrl  : inout AxiStreamCtrlArray;
215	      remRxLinkReady : inout sl;
216	      version        : inout slv(7 downto 0)) is
217	   begin
218	      version        := linkInfo(7 downto 0);
219	      remRxLinkReady := linkInfo(8);
220	      for i in remRxFifoCtrl'range loop
221	         remRxFifoCtrl(i).pause := linkInfo(i+16);
222	      end loop;
223	   end procedure;
224	
225	   function pgp4KCodeCrc (
226	      kCodeWord : slv(63 downto 0))
227	      return slv
228	   is
229	      -- G(X) = x^8 + x^3 + x^2 + x^1 + 1
230	      -- https://users.ece.cmu.edu/~koopman/crc/c08/0x83.txt
231	      constant CRC_POLY_C : slv(7 downto 0) := X"07";
232	
233	      variable data : slv(55 downto 0);
234	      variable fb   : slv(7 downto 0);
235	      variable ret  : slv(7 downto 0) := (others => '1');
236	   begin
237	
238	      -- Gather the non-contiguous input bits
239	      data(47 downto 0)  := kCodeWord(47 downto 0);
240	      data(55 downto 48) := kCodeWord(63 downto 56);
241	
242	      -- Reverse the input
243	      data := bitReverse(data);
244	
245	      -- Apply the CRC algorithm
246	      for d in 0 to 55 loop
247	         fb  := (others => (ret(7) xor data(d)));
248	         ret := ret(6 downto 0) & fb(0);
249	         ret := (fb and CRC_POLY_C) xor ret;
250	      end loop;
251	
252	      -- Transpose and invert the output
253	      ret := bitReverse(ret);
254	      ret := not ret;
255	
256	      return ret;
257	   end function;
258	
