55	      phyTxReady  : in  sl;
56	      phyTxValid  : out sl;
57	      phyTxStart  : out sl;
58	      phyTxData   : out slv(63 downto 0);
59	      phyTxHeader : out slv(1 downto 0);
60	
61	      -- Rx User interface
62	      pgpRxClk     : in  sl;
63	      pgpRxRst     : in  sl;
64	      pgpRxIn      : in  Pgp3RxInType := PGP3_RX_IN_INIT_C;
65	      pgpRxOut     : out Pgp3RxOutType;
66	      pgpRxMasters : out AxiStreamMasterArray(NUM_VC_G-1 downto 0);
67	      pgpRxCtrl    : in  AxiStreamCtrlArray(NUM_VC_G-1 downto 0);
